	st_mgr_no, ed_mgr_no, net_gbn_cd, link_gbn_cd, cable_typ, cable_desc, conn_stat, net_nm, line_color, ring_no, theme_mgr_no
	, _geometry
) VALUES (
	#{stMgrNo}, #{edMgrNo}, #{netGbnCd}, #{linkGbnCd}, #{cableTyp}, #{cableDesc}, #{connStat}, #{netNm}, #{lineColor}, #{ringNo}, #{themeMgrNo}::numeric

	, ST_SetSrid(ST_GeomFromeWkt(#{wkt}), 5186)
);

